class Solution:
    def largestInteger(self, num: int) -> int:
        str_num = str(num)
        odd, even = [], []
        for char in str_num:
            if int(char) % 2:
                odd.append(char)
            else:
                even.append(char)
        odd.sort(reverse=True)
        even.sort(reverse=True)
        result = ''
        for char in str_num:
            if int(char) % 2:
                result += odd.pop(0)
            else:
                result += even.pop(0)
        return int(result)
